import { BtcHotWallet } from '../wallet';
import { default as TransactionTool } from './TransactionTool';
import { SendParams, TransferParams } from '../types';
import { RuneSendParams } from '../runes';

export default class HotWalletTool extends TransactionTool<BtcHotWallet> {
    constructor(wallet: BtcHotWallet);
    send({ utxos, feeRate, changeAddress, outputs }: SendParams): import('..').TxDetail;
    transfer({ utxos, feeRate, recipient, changeAddress, transferUTXOs, }: TransferParams): import('..').TxDetail;
    sendRune(sendParams: RuneSendParams): import('..').TxDetail;
}
